'use client';

import { SWRProvider } from '@/app/components/providers/SWRProvider';
import { Sidebar } from '@/app/components/layout/Sidebar';
import { ConnectButton } from '@/app/components/shared/ConnectButton';
import { useSWRConfig } from 'swr';

export default function MainLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const { mutate } = useSWRConfig();

  const handleConnectSuccess = () => {
    // trigger global revalidation, same logic as before
    mutate(() => true, undefined, { revalidate: true });
  };

  return (
    <SWRProvider>
      <div className="flex min-h-screen bg-[#0d1117]">
        <Sidebar />
        <div className="flex-1 flex flex-col">
          {/* top bar with connect on the right */}
          <header className="flex justify-end p-4 bg-[#161b22] border-b border-[#30363d]">
            <ConnectButton onSuccess={handleConnectSuccess} />
          </header>
          <main className="flex-1 overflow-auto">
            {children}
          </main>
        </div>
      </div>
    </SWRProvider>
  );
}
